const inputItems = $input.all(); // all items passed to this node
const results = [];

for (const item of inputItems) {
  const inputData = item.json;

  let processedData = {
    domain: null,
    targetUrl: '',
    totalBacklinks: 0,
    topBacklinks: [],
    summary: {
      avgRank: 0,
      dofollowCount: 0,
      nofollowCount: 0,
      brokenLinks: 0,
      avgSpamScore: 0
    },
    processed_at: new Date().toISOString(),
    error: null
  };

  try {
    if (inputData && inputData.tasks && inputData.tasks[0] && inputData.tasks[0].result && inputData.tasks[0].result[0]) {
      const result = inputData.tasks[0].result[0];
      const items = result.items || [];

      processedData.domain = result.target;
      processedData.targetUrl = result.target;
      processedData.totalBacklinks = result.total_count || 0;

      let totalRank = 0;
      let totalSpamScore = 0;

      items.forEach(item => {
        const backlink = {
          fromDomain: item.domain_from,
          fromUrl: item.url_from,
          anchor: item.anchor || 'No anchor text',
          rank: item.rank || 0,
          domainRank: item.domain_from_rank || 0,
          spamScore: item.backlink_spam_score || 0,
          dofollow: item.dofollow || false,
          isBroken: item.is_broken || false,
          firstSeen: item.first_seen,
          lastSeen: item.last_seen,
          linkType: item.item_type,
          pageTitle: item.page_from_title || 'Unknown'
        };

        processedData.topBacklinks.push(backlink);
        totalRank += backlink.rank;
        totalSpamScore += backlink.spamScore;

        backlink.dofollow ? processedData.summary.dofollowCount++ : processedData.summary.nofollowCount++;
        if (backlink.isBroken) processedData.summary.brokenLinks++;
      });

      if (items.length > 0) {
        processedData.summary.avgRank = Math.round(totalRank / items.length);
        processedData.summary.avgSpamScore = Math.round(totalSpamScore / items.length);
      }

    } else {
      processedData.error = 'Invalid API response format';
    }
  } catch (error) {
    processedData.error = `Processing error: ${error.message}`;
  }

  results.push({ json: processedData });
}

return results;

// Generate timestamp 24 hours BEFORE now (IST)
const IST_OFFSET = 5.5 * 60 * 60 * 1000; // IST offset in milliseconds
const date = new Date(Date.now() - 24 * 60 * 60 * 1000 + IST_OFFSET);

const pad = (n) => (n < 10 ? '0' + n : n);

const time = `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())} +05:30`;


