function formatNumber(num) {
  return new Intl.NumberFormat().format(num);
}

function getTierBadge(tier) {
  const colors = {
    '1': { bg: '#10b981', text: 'Tier 1' },
    '2': { bg: '#f59e0b', text: 'Tier 2' },
    '3': { bg: '#ef4444', text: 'Tier 3' }
  };
  const config = colors[tier] || { bg: '#6b7280', text: `Tier ${tier}` };
  return `<span style="background: ${config.bg}; color: white; padding: 4px 12px; border-radius: 16px; font-size: 0.75rem; font-weight: 600; display: inline-block;">${config.text}</span>`;
}

function truncateUrl(url, maxLength = 50) {
  if (!url) return '-';
  if (url.length <= maxLength) return url;
  return url.substring(0, maxLength) + '...';
}

function extractDomain(url) {
  if (!url) return '-';
  try {
    return new URL(url).hostname.replace('www.', '');
  } catch {
    return url.replace(/^https?:\/\/(www\.)?/, '').split('/')[0];
  }
}

function formatDate(dateStr) {
  if (!dateStr || dateStr === 'N/A') return 'N/A';
  try {
    return new Date(dateStr).toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'short', 
      day: 'numeric' 
    });
  } catch {
    return dateStr;
  }
}

