    text += `${'-'.repeat(80)}\n`;
    data.accepted.forEach((link, index) => {
      text += `${index + 1}. ${extractDomain(link.url)}\n`;
      text += `   URL: ${link.url}\n`;
      text += `   Anchor: ${link.anchor}\n`;
      text += `   Rank: ${link.rank} | Domain Rank: ${link.domain_rank} | Score: ${link.score}\n`;
      text += `   Spam: ${link.spam_score} | Follow: ${link.do_follow} | Tier: ${link.tier}\n`;
      text += `   Type: ${link.link_type}\n`;
      text += `   First Seen: ${formatDate(link.first_seen)} | Last Seen: ${formatDate(link.last_seen)}\n`;
      text += `   Reason: ${link.reason}\n\n`;
    });
  }

  if (data.rejected.length > 0) {
    text += `\n❌ REJECTED BACKLINKS (${data.rejected.length}):\n`;
    text += `${'-'.repeat(80)}\n`;
    data.rejected.forEach((link, index) => {
      text += `${index + 1}. ${extractDomain(link.url)}\n`;
      text += `   URL: ${link.url}\n`;
      text += `   Rank: ${link.rank} | Domain Rank: ${link.domain_rank} | Score: ${link.score}\n`;
      text += `   Spam: ${link.spam_score} | Follow: ${link.do_follow}\n`;
      text += `   Rejection Reason: ${link.reason}\n\n`;
    });
  }
});

text += `\n${'='.repeat(80)}\n`;
text += `Report Generated: ${new Date().toISOString()}\n`;
text += `${'='.repeat(80)}\n`;

// Email subject
const subject = `Backlink Analysis Report - ${currentDate} | ${totalDomains} Domains | ${totalAccepted} Accepted / ${totalRejected} Rejected`;

// Return data for N8N
return {
  json: {
    subject: subject,
    htmlBody: html,
    textBody: text,
    summary: {
      total_domains: totalDomains,
      total_links: totalLinks,
      accepted: totalAccepted,
      rejected: totalRejected,
      quality_rate: totalLinks > 0 ? ((totalAccepted / totalLinks) * 100).toFixed(1) : 0,
      generated_at: new Date().toISOString()
    }
  }
};

// Log successful completion with summary stats
const emailData = $input.first().json;

console.log('✅ Enhanced backlink report sent successfully!');
console.log(`📊 Report Summary:`);
console.log(`   - Domains: ${emailData.summary.total_domains}`);
console.log(`   - Total Backlinks: ${emailData.summary.total_backlinks.toLocaleString()}`);
console.log(`   - Dofollow Links: ${emailData.summary.total_dofollow}`);
console.log(`   - Broken Links: ${emailData.summary.total_broken}`);
console.log(`   - Generated: ${emailData.summary.generated_at}`);

// Return success status
return [{
    json: {
        success: true,
        message: 'Enhanced backlink report processed and sent successfully',
        timestamp: new Date().toISOString(),
        summary: emailData.summary
    }
}];
